import React, { useEffect, useState } from 'react';
import { fetchPlans, createPlan, deletePlan } from './api';

function App() {
  const [plans, setPlans] = useState([]);
  const [formData, setFormData] = useState({ examType: 'KPSS Lisans', topics: '', studyTime: '' });

  useEffect(() => {
    loadPlans();
  }, []);

  const loadPlans = async () => {
    const { data } = await fetchPlans();
    setPlans(data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const topicsArray = formData.topics.split(',').map(t => t.trim());
    await createPlan({ ...formData, topics: topicsArray });
    setFormData({ examType: 'KPSS Lisans', topics: '', studyTime: '' });
    loadPlans(); // Listeyi güncelle
  };

  const handleDelete = async (id) => {
    await deletePlan(id);
    loadPlans();
  };

  return (
    <div className="min-h-screen bg-[#FEFAE0] p-8 font-sans"> {/* Butter Yellow Arka Plan */}
      <div className="max-w-2xl mx-auto">
        <h1 className="text-4xl font-bold text-[#F8AD9D] mb-8 text-center">Planly 🌸</h1>

        {/* Plan Oluşturma Formu */}
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm mb-10 border border-[#E9EDC9]">
          <div className="grid grid-cols-1 gap-4">
            <input 
              className="p-3 rounded-xl border border-[#CCD5AE] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D]"
              placeholder="Sınav Türü (örn: KPSS Lisans)"
              value={formData.examType}
              onChange={(e) => setFormData({...formData, examType: e.target.value})}
            />
            <input 
              className="p-3 rounded-xl border border-[#CCD5AE] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D]"
              placeholder="Konular (Virgülle ayırın)"
              value={formData.topics}
              onChange={(e) => setFormData({...formData, topics: e.target.value})}
            />
            <input 
              className="p-3 rounded-xl border border-[#CCD5AE] focus:outline-none focus:ring-2 focus:ring-[#F8AD9D]"
              placeholder="Çalışma Süresi (Saat)"
              type="number"
              value={formData.studyTime}
              onChange={(e) => setFormData({...formData, studyTime: e.target.value})}
            />
            <button className="bg-[#F8AD9D] text-white p-3 rounded-xl font-bold hover:bg-[#F4978E] transition-all">
              Planı Kaydet ✨
            </button>
          </div>
        </form>

        {/* Plan Listesi */}
        <div className="grid gap-4">
          {plans.map((plan) => (
            <div key={plan._id} className="bg-white p-5 rounded-2xl shadow-sm flex justify-between items-center border-l-8 border-[#B5E48C]"> {/* Soft Green Kenarlık */}
              <div>
                <h3 className="text-xl font-bold text-[#6B705C]">{plan.examType}</h3>
                <p className="text-[#A5A5A5]">{plan.topics.join(' • ')}</p>
                <span className="inline-block mt-2 text-xs font-bold bg-[#FAEDCD] text-[#D4A373] px-2 py-1 rounded">
                  ⏱ {plan.studyTime} Saat
                </span>
              </div>
              <button 
                onClick={() => handleDelete(plan._id)}
                className="text-[#F8AD9D] hover:text-red-400 font-bold p-2"
              >
                Sil
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
